def _merged_value(self, key: str, value: FeatureType) -> FeatureType:
    """Return the value to store for ``key``, deep-merging it into the existing value when both are dictionaries.

    If ``key`` is already present and both the current and new values are dictionaries (this also covers
    nested :class:`Features` or a :class:`Sequence` whose ``feature`` is a dictionary), the new dictionary is
    merged into the existing one in place instead of replacing it outright.
    """
    if key not in self:
        return value
    current = self[key]
    current_dict = current.feature if isinstance(current, Sequence) else current
    value_dict = value.feature if isinstance(value, Sequence) else value
    if isinstance(current_dict, dict) and isinstance(value_dict, dict):
        current_dict.update(value_dict)
        return current
    return value

